import dataclasses
from typing import Any, Dict, List, Optional, Tuple, Type, TypeVar, Union, get_origin, get_args

T = TypeVar('T')

def to_dict(obj: Any) -> Any:
    if dataclasses.is_dataclass(obj):
        result = {}
        for field in dataclasses.fields(obj):
            value = getattr(obj, field.name)
            result[field.name] = to_dict(value)
        return result
    elif isinstance(obj, (list, tuple)):
        return type(obj)(to_dict(item) for item in obj)
    elif isinstance(obj, dict):
        return {to_dict(key): to_dict(value) for key, value in obj.items()}
    else:
        return obj

def from_dict(data: Dict[str, Any], dataclass_type: Type[T]) -> T:
    if not dataclasses.is_dataclass(dataclass_type):
        raise TypeError(f"'{dataclass_type}' is not a dataclass type.")

    field_values = {}
    for field in dataclasses.fields(dataclass_type):
        field_name = field.name
        field_type = field.type

        if field_name not in data:
            if field.default is not dataclasses.MISSING:
                field_values[field_name] = field.default
                continue
            elif field.default_factory is not dataclasses.MISSING:
                field_values[field_name] = field.default_factory()
                continue
            # If a required field is missing and no default, dataclass constructor will raise TypeError.
            # We can skip and let it fail there or raise here.
            # For now, let's pass None and let dataclass constructor handle required fields.
            field_value = None
        else:
            field_value = data[field_name]

        if field_value is None:
            field_values[field_name] = None
            continue

        origin = get_origin(field_type)
        args = get_args(field_type)

        if dataclasses.is_dataclass(field_type):
            field_values[field_name] = from_dict(field_value, field_type)
        elif origin is list:
            item_type = args[0] if args else Any
            if dataclasses.is_dataclass(item_type):
                field_values[field_name] = [from_dict(item, item_type) for item in field_value]
            else:
                field_values[field_name] = field_value
        elif origin is tuple:
            if args and args[-1] is Ellipsis:
                item_type = args[0]
                if dataclasses.is_dataclass(item_type):
                    field_values[field_name] = tuple(from_dict(item, item_type) for item in field_value)
                else:
                    field_values[field_name] = field_value
            elif args:
                deserialized_tuple = []
                for i, item in enumerate(field_value):
                    item_type = args[i] if i < len(args) else Any
                    if dataclasses.is_dataclass(item_type):
                        deserialized_tuple.append(from_dict(item, item_type))
                    else:
                        deserialized_tuple.append(item)
                field_values[field_name] = tuple(deserialized_tuple)
            else:
                field_values[field_name] = field_value
        elif origin is dict:
            key_type = args[0] if args else Any
            value_type = args[1] if args and len(args) > 1 else Any
            if dataclasses.is_dataclass(value_type):
                field_values[field_name] = {k: from_dict(v, value_type) for k, v in field_value.items()}
            else:
                field_values[field_name] = field_value
        elif origin is Union:
            actual_types = tuple(arg for arg in args if arg is not type(None))

            deserialized_union_value = field_value
            for actual_type in actual_types:
                try:
                    if dataclasses.is_dataclass(actual_type) and isinstance(field_value, dict):
                        deserialized_union_value = from_dict(field_value, actual_type)
                        break
                    elif not dataclasses.is_dataclass(actual_type) and isinstance(field_value, actual_type):
                        deserialized_union_value = field_value
                        break
                except (TypeError, AttributeError, KeyError, ValueError):
                    continue
            field_values[field_name] = deserialized_union_value
        else:
            field_values[field_name] = field_value

    return dataclass_type(**field_values)
